oxy_webhelp_navlinks = {"rcv_cust_managed_migration_process-d26997e7951":{"topics":[{"title":"Preparing for customer-hosted migration","shortdesc":"<p class=\"shortdesc\">Prepare the source location for migration by validating source location eligibility,         disabling archival locations, and updating encryption keys.<\/p>","href":"saas\/rcv_preparing_customer_hosted_migration.html","attributes":{"data-id":"rcv_preparing_customer_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_preparing_customer_hosted_migration-d26997e7962","topics":[]},{"title":"Configuring customer-hosted migration","shortdesc":"<p class=\"shortdesc\">Configure the security permissions required for AWS DataSync to move data, including         fetching bucket names, creating IAM roles, and registering destination roles with <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/rcv_configuring_cust_hosted_migration.html","attributes":{"data-id":"rcv_configuring_cust_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_configuring_cust_hosted_migration-d26997e7973","topics":[]},{"title":"Running the customer-hosted migration task","shortdesc":"<p class=\"shortdesc\">Create and start the AWS DataSync transfer task to migrate data from the source         location to the destination RCV bucket.<\/p>","href":"saas\/rcv_running_cust_hosted_migration.html","attributes":{"data-id":"rcv_running_cust_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_running_cust_hosted_migration-d26997e7987","topics":[]},{"title":"Finalizing customer-hosted migration","shortdesc":"<p class=\"shortdesc\">After the data transfer is complete, perform the final configuration and validation         steps to finalize the transition to the RCV location.<\/p>","href":"saas\/rcv_finalizing_customer_hosted_migration.html","attributes":{"data-id":"rcv_finalizing_customer_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_finalizing_customer_hosted_migration-d26997e7998","topics":[]}]}};